---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends Omit<HTMLAttributes<"input">, "type"> {}

const { class: className, ...props } = Astro.props
---

<input
  type="radio"
  role="radio"
  data-slot="radio-group-item"
  class={cn(
    "border-input dark:bg-input/30 checked:bg-primary checked:text-primary-foreground dark:checked:bg-primary checked:border-primary aria-invalid:checked:border-primary aria-invalid:border-destructive focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 dark:aria-invalid:border-destructive/50 group/radio-group-item peer relative flex aspect-square size-4 shrink-0 appearance-none rounded-full border outline-none after:absolute after:-inset-x-3 after:-inset-y-2 focus-visible:ring-3 disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:ring-3",
    className
  )}
  {...props}
/>

<style>
  [data-slot="radio-group-item"]::before {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    width: 0.5rem;
    height: 0.5rem;
    transform: translate(-50%, -50%);
    border-radius: 9999px;
    background: var(--primary-foreground);
    opacity: 0;
  }

  [data-slot="radio-group-item"]:checked::before {
    opacity: 1;
  }
</style>
